section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/aws-cfn-terraform-templates.json",
  "type": "object",
  "required": [
    "artefact_id",
    "template_pattern",
    "region",
    "account_id",
    "encryption_at_rest",
    "deletion_protection",
    "iam_least_privilege",
    "mandatory_tags_present",
    "owner"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "stable id"
    },
    "template_pattern": {
      "type": "string",
      "description": "enum: vpc | ecs-fargate | lambda-api | rds-postgres"
    },
    "region": {
      "type": "string",
      "description": "AWS region code"
    },
    "account_id": {
      "type": "string",
      "description": "12-digit AWS account id"
    },
    "encryption_at_rest": {
      "type": "boolean",
      "description": "true for production"
    },
    "deletion_protection": {
      "type": "boolean",
      "description": "true for production stateful resources"
    },
    "iam_least_privilege": {
      "type": "boolean",
      "description": "true (no Resource: '*' or Action: '*')"
    },
    "mandatory_tags_present": {
      "type": "array",
      "description": "must contain ['Project', 'Environment', 'Owner', 'CostCenter', 'ManagedBy']"
    },
    "owner": {
      "type": "string",
      "description": "single named handle"
    }
  }
}
